function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill().map(() => ({})));
    dp[0][0][1] = (0 + 1) * (0 + 1); // initial cost at step 1

    let minCost = Infinity;
    const queue = [[0, 0, 1]]; // [i, j, step]

    while (queue.length > 0) {
        const [i, j, step] = queue.shift();
        const currentCost = dp[i][j][step];

        if (i === m - 1 && j === n - 1) {
            minCost = Math.min(minCost, currentCost);
            continue;
        }

        if (step % 2 === 1) { // odd step: move right or down
            // move right
            if (j + 1 < n) {
                const newJ = j + 1;
                const newStep = step + 1;
                const moveCost = (i + 1) * (newJ + 1);
                const totalCost = currentCost + moveCost;

                if (!dp[i][newJ][newStep] || totalCost < dp[i][newJ][newStep]) {
                    dp[i][newJ][newStep] = totalCost;
                    queue.push([i, newJ, newStep]);
                }
            }
            // move down
            if (i + 1 < m) {
                const newI = i + 1;
                const newStep = step + 1;
                const moveCost = (newI + 1) * (j + 1);
                const totalCost = currentCost + moveCost;

                if (!dp[newI][j][newStep] || totalCost < dp[newI][j][newStep]) {
                    dp[newI][j][newStep] = totalCost;
                    queue.push([newI, j, newStep]);
                }
            }
        } else { // even step: wait
            const newStep = step + 1;
            const waitCostHere = waitCost[i][j];
            const totalCost = currentCost + waitCostHere;

            if (!dp[i][j][newStep] || totalCost < dp[i][j][newStep]) {
                dp[i][j][newStep] = totalCost;
                queue.push([i, j, newStep]);
            }
        }
    }

    return minCost;
}

