use std::collections::VecDeque;

fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m = m as usize;
    let n = n as usize;
    let mut dp = vec![vec![std::collections::HashMap::new(); n]; m];
    dp[0][0].insert(1, (0 + 1) * (0 + 1));

    let mut min_cost = i64::MAX;
    let mut queue = VecDeque::new();
    queue.push_back((0, 0, 1));

    while let Some((i, j, step)) = queue.pop_front() {
        let current_cost = *dp[i][j].get(&step).unwrap();

        if i == m - 1 && j == n - 1 {
            min_cost = min_cost.min(current_cost);
            continue;
        }

        if step % 2 == 1 {
            // Move right
            if j + 1 < n {
                let new_j = j + 1;
                let new_step = step + 1;
                let move_cost = (i as i64 + 1) * (new_j as i64 + 1);
                let total_cost = current_cost + move_cost;

                if !dp[i][new_j].contains_key(&new_step) || total_cost < *dp[i][new_j].get(&new_step).unwrap() {
                    dp[i][new_j].insert(new_step, total_cost);
                    queue.push_back((i, new_j, new_step));
                }
            }
            // Move down
            if i + 1 < m {
                let new_i = i + 1;
                let new_step = step + 1;
                let move_cost = (new_i as i64 + 1) * (j as i64 + 1);
                let total_cost = current_cost + move_cost;

                if !dp[new_i][j].contains_key(&new_step) || total_cost < *dp[new_i][j].get(&new_step).unwrap() {
                    dp[new_i][j].insert(new_step, total_cost);
                    queue.push_back((new_i, j, new_step));
                }
            }
        } else {
            // Wait
            let new_step = step + 1;
            let wait_cost_here = waitCost[i][j];
            let total_cost = current_cost + wait_cost_here;

            if !dp[i][j].contains_key(&new_step) || total_cost < *dp[i][j].get(&new_step).unwrap() {
                dp[i][j].insert(new_step, total_cost);
                queue.push_back((i, j, new_step));
            }
        }
    }

    min_cost
}
